import{_ as a,o as p,c as l,a5 as o}from"./chunks/framework.B5tqjWbr.js";const _=JSON.parse('{"title":"教程 0032：UPS 命令解析与安全门控","description":"","frontmatter":{"title":"教程 0032：UPS 命令解析与安全门控","date":"2026-07-02T00:00:00.000Z","section":"电源控制","chapter":"01-Lessons","chapterTitle":"电源课程","category":"电源控制","tags":["imported"],"source":"power","sourcePath":"0032-ups-command-parser.html","status":"learning","visibility":"public","summary":"Imported from 0032-ups-command-parser.html","chapterOrder":10},"headers":[],"relativePath":"content/power/lessons/0032-ups-command-parser.md","filePath":"content/power/lessons/0032-ups-command-parser.md","lastUpdated":null}'),r={name:"content/power/lessons/0032-ups-command-parser.md"};function t(i,e,s,d,c,n){return p(),l("div",null,[...e[0]||(e[0]=[o(`<h1 id="教程-0032-ups-命令解析与安全门控" tabindex="-1">教程 0032：UPS 命令解析与安全门控 <a class="header-anchor" href="#教程-0032-ups-命令解析与安全门控" aria-label="Permalink to &quot;教程 0032：UPS 命令解析与安全门控&quot;">​</a></h1><p>中文主讲。一个概念：外部通信命令只能先变成动作意图，真正影响故障锁存前必须经过安全门控。</p><pre><code>目录
</code></pre><ul><li><p>它是什么</p></li><li><p>为什么 UPS 需要它</p></li><li><p>物理直觉</p></li><li><p>数学形式</p></li><li><p>一个仿真任务与仿真观察</p></li><li><p>固件落地</p></li><li><p>常见误解</p></li><li><p>验收标准、复盘问题、导师问题</p></li></ul><p>**保密边界：**本节只使用教学命令，不包含公司内部通信命令、寄存器地址、客户项目参数或未公开产品方案。</p><h2 id="_1-它是什么" tabindex="-1">1. 它是什么 <a class="header-anchor" href="#_1-它是什么" aria-label="Permalink to &quot;1. 它是什么&quot;">​</a></h2><p>命令解析（command parsing）是把外部通信收到的文本、字节或寄存器请求转换成固件内部动作意图的过程。安全门控（safety gating）是在动作真正生效前，再检查系统是否满足安全条件。</p><p>本课只讲一个概念：通信命令不能直接改安全状态。教学命令只包含两类：</p><ul><li><p><code>READ_STATUS</code>：请求遥测（telemetry）回复。</p></li><li><p><code>CLEAR_FAULT_REQUEST</code>：清故障请求（clear fault request），必须经过安全门控后才能变成真正的清故障动作。</p></li></ul><h2 id="_2-为什么-ups-需要它" tabindex="-1">2. 为什么 UPS 需要它 <a class="header-anchor" href="#_2-为什么-ups-需要它" aria-label="Permalink to &quot;2. 为什么 UPS 需要它&quot;">​</a></h2><p>UPS 通信模块会收到外部工具、监控系统或调试脚本发来的请求。如果通信命令绕过保护逻辑，直接清除故障锁存（fault latch）或打开输出，就会破坏系统安全边界。</p><p>因此阅读 UPS C 工程时，要把“收到命令”和“执行命令”分开看：命令解析只产生意图，安全门控决定这个意图是否允许落地。</p><h2 id="_3-物理直觉" tabindex="-1">3. 物理直觉 <a class="header-anchor" href="#_3-物理直觉" aria-label="Permalink to &quot;3. 物理直觉&quot;">​</a></h2><p>命令解析像门卫看懂访客想做什么；安全门控像值班工程师判断现在能不能放行。访客说“我要清故障”并不代表设备立刻清故障，必须满足市电、负载、输出、故障原因等安全条件。</p><h2 id="_4-数学形式" tabindex="-1">4. 数学形式 <a class="header-anchor" href="#_4-数学形式" aria-label="Permalink to &quot;4. 数学形式&quot;">​</a></h2><p>command = parse(raw_command)</p><p>if command.type == READ_STATUS: request_telemetry_reply = 1</p><p>if command.type == CLEAR_FAULT_REQUEST: request_clear_fault = 1</p><p>if request_clear_fault and not safe_to_clear_fault: request_clear_fault = 0</p><p>本课只用一个布尔量 <code>safe_to_clear_fault</code> 表示安全条件，真实工程可能由模式、输出反馈、故障原因、保持时间和人工确认共同决定。</p><h2 id="_5-一个仿真任务与仿真观察" tabindex="-1">5. 一个仿真任务与仿真观察 <a class="header-anchor" href="#_5-一个仿真任务与仿真观察" aria-label="Permalink to &quot;5. 一个仿真任务与仿真观察&quot;">​</a></h2><p>运行 Python 仿真：</p><p>cd E:\\gitee_CodeStorage\\学习\\电源 python simulations\\python\\ups_command_parser.py</p><p>只保存图片、不自动打开：</p><p>python simulations\\python\\ups_command_parser.py --no-open</p><pre><code>产物
</code></pre><ul><li><p><code>simulations/results/ups_command_parser.png</code></p></li><li><p>终端输出：不安全清故障是否被接受、安全清故障是否被接受、请求遥测回复次数。</p></li><li><p>图内包含参数框、图例、命令类型、遥测回复请求、清故障请求和安全门控状态。</p></li></ul><p>观察顺序：先看 <code>READ_STATUS</code> 只产生遥测回复请求；再看 20 ms 的不安全清故障被拒绝；最后看 60 ms 安全条件成立后，清故障请求才通过。</p><h2 id="_6-固件落地" tabindex="-1">6. 固件落地 <a class="header-anchor" href="#_6-固件落地" aria-label="Permalink to &quot;6. 固件落地&quot;">​</a></h2><ul><li><p><code>UpsCommandType</code>：教学命令类型。</p></li><li><p><code>UPS_COMMAND_READ_STATUS</code>：读取状态命令。</p></li><li><p><code>UPS_COMMAND_CLEAR_FAULT_REQUEST</code>：清故障请求命令。</p></li><li><p><code>UpsCommand</code>：解析后的内部命令意图。</p></li><li><p><code>request_telemetry_reply</code>：是否需要回复通信帧（communication frame）。</p></li><li><p><code>request_clear_fault</code>：是否请求清除故障锁存。</p></li><li><p><code>UpsCommand_Parse()</code>：把原始命令转换成内部意图。</p></li><li><p><code>UpsCommand_ApplySafetyGate()</code>：在安全条件不满足时拦截清故障请求。</p></li></ul><p>真实工程中还会有校验、超时、权限、主从地址、协议状态机和错误响应。本课不实现真实协议，只训练“解析”和“安全门控”的边界。</p><h2 id="_7-常见误解" tabindex="-1">7. 常见误解 <a class="header-anchor" href="#_7-常见误解" aria-label="Permalink to &quot;7. 常见误解&quot;">​</a></h2><ul><li><p>**误解：**通信命令解析成功就应该立即执行。 **纠正：**解析成功只说明看懂了命令，不代表动作安全。</p></li><li><p>**误解：**清故障只是把标志清零。 **纠正：**清故障会影响系统重新启动和输出许可，必须经过安全条件检查。</p></li><li><p>**误解：**可以把导师给的真实命令字记到学习仓库。 **纠正：**不能记录公司内部通信命令，只能记录通用解析流程和安全边界。</p></li></ul><h2 id="_8-验收标准" tabindex="-1">8. 验收标准 <a class="header-anchor" href="#_8-验收标准" aria-label="Permalink to &quot;8. 验收标准&quot;">​</a></h2><ul><li><p>能运行 <code>python simulations\\python\\ups_command_parser.py --no-open</code> 并打开 <code>simulations/results/ups_command_parser.png</code>。</p></li><li><p>能解释命令解析和安全门控的区别。</p></li><li><p>能解释为什么 <code>CLEAR_FAULT_REQUEST</code> 不能直接清除故障锁存。</p></li><li><p>能编译并运行 <code>projects/03-ups-c-firmware-skeleton</code>，看到 <code>command_parser</code> 输出。</p></li><li><p>能基于 <code>command_parser.c -&gt; UpsCommand_ApplySafetyGate()</code> 准备导师问题。</p></li></ul><h2 id="_9-复盘问题" tabindex="-1">9. 复盘问题 <a class="header-anchor" href="#_9-复盘问题" aria-label="Permalink to &quot;9. 复盘问题&quot;">​</a></h2><ul><li><p>为什么“解析成功”和“允许执行”必须分开？</p></li><li><p>为什么清故障请求比读状态请求危险？</p></li><li><p>如果安全条件不满足，通信模块应该沉默、回复错误还是回复当前状态？各有什么取舍？</p></li></ul><h2 id="_10-导师问题" tabindex="-1">10. 导师问题 <a class="header-anchor" href="#_10-导师问题" aria-label="Permalink to &quot;10. 导师问题&quot;">​</a></h2><ul><li><p>我用 <code>command_parser.c -&gt; UpsCommand_ApplySafetyGate()</code> 把清故障请求和安全条件分开。真实工程里清故障通常需要检查哪些通用条件？</p></li><li><p>我用 <code>simulations/results/ups_command_parser.png</code> 看到不安全清故障被拒绝。真实工程中拒绝命令时通常会回复错误码、保持沉默，还是上报当前状态？</p></li><li><p>我不会记录公司内部通信命令，只想确认阅读方式：看真实工程通信模块时，应先找命令解析表、安全门控入口，还是故障复位流程？</p></li></ul><p>**下一步：**可以继续补“命令响应与错误码”，训练请求失败时如何把原因反馈给外部工具。</p><p>关联：<a href="./0031-ups-telemetry-frame.html">上一节：UPS 遥测通信帧</a>；源稿：<code>concepts/embedded/ups-command-parser.md</code>；仿真：<code>simulations/python/ups_command_parser.py</code>。</p><pre><code>上一节：教程 0031：UPS 遥测通信帧
下一节：教程 0033：UPS 命令响应与拒绝原因
</code></pre>`,42)])])}const u=a(r,[["render",t]]);export{_ as __pageData,u as default};
